import './App.css';
import Banner  from './component/Banner';
import { useState } from 'react';
import React from 'react';
import loginImg from './img/kitchen.png'

// import {Redirect} from 'react-router-dom';



function App({ history }) {
//   const fname=sakshi;
// const lname =jain;
const [name,setName]=useState("");
const [fname,setFname]=useState("");


const inputEvent=(event)=>{
  setName(event.target.value)
}
const submit=()=>{
  setFname(name);
  setName("");
}

  return (
    <div className="App " >

<div>
{/* <h1 >hello my name is {fname} </h1> */}

{
fname==0?
<div className='inputField'>
  <div className='box  d-flex justify-content-center align-items-center mx-auto'>
  <div className='box-img'>
    <img className='w-100' src={loginImg}/>
    </div>
    <div className='box-input d-flex justify-content-center align-items-center gap-2 '>
  <h5 className='text-white text-capitalize mb-0' >enter name here</h5>
  <input type="text"  onChange={inputEvent} value={name} className='input-box'/>
  <button onClick={submit}>submit</button>
</div>
</div>
</div>:<><Banner value={fname} />

</>
  }

</div>
    </div>
  );
}

export default App;
